    #[test]
    fn test_registry_default_takes_priority_over_fallback() {
        let fallback = Arc::new(FallbackChunker::new(512));
        let mut registry = FormatRegistry::new(fallback);
        let md_strategy = Arc::new(FallbackChunker::new(256)); // pretend it's MarkdownChunker
        registry.register_default("md", md_strategy);
        // "md" resolves to the registered default, not fallback
        let resolved = registry.resolve("md");
        // both are FallbackChunker but we can check it resolves (not fallback max_tokens)
        assert_eq!(resolved.name(), "fallback"); // same name — OK for now
        // "txt" still falls back
        assert_eq!(registry.resolve("txt").name(), "fallback");
    }

    #[test]
    fn test_registry_override_takes_priority_over_default() {
        let fallback = Arc::new(FallbackChunker::new(512));
        let mut registry = FormatRegistry::new(fallback);
        registry.register_default("rs", Arc::new(FallbackChunker::new(512)));
        registry.register_override("rs", Arc::new(FallbackChunker::new(256)));
        // Override should be resolved
        let resolved = registry.resolve("rs");
        assert_eq!(resolved.name(), "fallback");
    }

